  }
}
.moonlit-service__cell {
  padding: clamp(1.2rem, 2.4svh, 1.6rem);
  background: linear-gradient(
    180deg,
    rgba(26, 34, 64, 0.42) 0%,
    rgba(19, 26, 46, 0.42) 100%
  );
  border: 1px solid var(--ml-hairline);
