}
.moonlit-service__celln {
  margin: 0 0 0.3rem;
  font-size: 0.92rem;
  line-height: 1.55;
  color: var(--ml-moonlight);
}
.moonlit-service__celln-en {
  margin: 0;
  font-size: 0.85rem;
  line-height: 1.5;
  color: var(--ml-moonlight-dim);
  font-style: italic;
}

.moonlit-service__cta {
  display: flex;
  flex-wrap: wrap;
  gap: 1rem;
  align-items: center;
}
.moonlit-service__btn {
  display: inline-flex;
  flex-direction: column;
  gap: 0.2em;
  padding: 1em 1.5em;
  background: var(--ml-neon);
  color: var(--ml-night-deep);
  text-decoration: none;
  border-radius: 2px;
