}

/* Footer */
.moonlit-footer {
  padding: clamp(50px, 8svh, 90px) var(--ml-gutter)
    clamp(50px, 8svh, 90px);
  border-top: 1px solid var(--ml-hairline);
  background: var(--ml-night-deep);
}
.moonlit-footer__grid {
  max-width: var(--ml-frame-w);
  margin: 0 auto;
  display: flex;
  flex-wrap: wrap;
  gap: 0.6rem 2.4rem;
  align-items: baseline;
  padding-bottom: clamp(1.4rem, 3svh, 2rem);
  border-bottom: 1px solid var(--ml-hairline);
}
.moonlit-footer__brand :lang(ko) {
  font-family: var(--ml-font-splash);
  font-size: 1.4rem;
  color: var(--ml-neon-bright);
}
.moonlit-footer__branden {
  margin-left: 0.6em;
  font-size: 0.74rem;
  letter-spacing: 0.2em;
  color: var(--ml-steel);
}
.moonlit-footer__meta {
  font-size: 0.76rem;
  letter-spacing: 0.12em;
  color: var(--ml-moonlight-dim);
}
.moonlit-footer__koan {
  max-width: var(--ml-frame-w);
  margin: clamp(1.6rem, 3svh, 2.4rem) auto 0.2rem;
  font-size: clamp(1.2rem, 2.4vw, 1.7rem);
  font-weight: 500;
  color: var(--ml-moonlight);
  line-height: 1.35;
}
.moonlit-footer__koan-en {
  max-width: var(--ml-frame-w);
  margin: 0 auto;
  font-size: 0.96rem;
  color: var(--ml-moonlight-dim);
  font-style: italic;
}
.moonlit-footer__base {
  max-width: var(--ml-frame-w);
  margin: clamp(1.6rem, 3svh, 2.4rem) auto 0;
  display: flex;
  flex-wrap: wrap;
  gap: 0.8rem 2rem;
  align-items: center;
  padding-top: clamp(1.2rem, 2svh, 1.6rem);
  border-top: 1px solid var(--ml-hairline);
}
.moonlit-footer__copy {
  font-size: 0.74rem;
  letter-spacing: 0.08em;
  color: var(--ml-steel);
}
.moonlit-footer__top {
  font-size: 0.74rem;
  letter-spacing: 0.18em;
  color: var(--ml-neon);
  text-decoration: none;
}
.moonlit-footer__top:hover {
  color: var(--ml-neon-bright);
}

/* ==========================================================================
   Scroll reveals — JS-gated pre-state, transform/opacity only
   ========================================================================== */

.moonlit-js [data-reveal] {
  opacity: 0;
  transform: translateY(18px);
  transition:
    opacity 600ms var(--ml-ease),
    transform 600ms var(--ml-ease);
  will-change: opacity, transform;
}
.moonlit-js [data-reveal].is-visible {
  opacity: 1;
  transform: none;
}

/* ==========================================================================
   Keyframes — transform / opacity / stroke / filter only
   ========================================================================== */

/* Neon flicker — a tired tube, mostly steady, two quick dips per cycle */
@keyframes ml-flicker {
  0%,
  100% {
    opacity: 1;
  }
  47% {
    opacity: 1;
  }
  48% {
    opacity: 0.62;
  }
  49% {
    opacity: 1;
  }
  78% {
    opacity: 1;
  }
  79% {
    opacity: 0.5;
  }
  80% {
    opacity: 1;
  }
}

/* Status dot — the page's only "live" indicator */
@keyframes ml-pulse {
  0%,
  100% {
    opacity: 1;
    transform: scale(1);
  }
  50% {
    opacity: 0.55;
    transform: scale(0.88);
  }
}

/* Typing cursor — blinking block */
@keyframes ml-blink {
  0%,
  49% {
    opacity: 1;
  }
  50%,
  100% {
    opacity: 0;
  }
}

/* Headlight trail — sweep across the panel. The row is 200% wide, so moving
   by -50% of itself equals one panel-width sweep, then it loops. */
@keyframes ml-trail {
  from {
    transform: translate3d(0, 0, 0);
  }
  to {
    transform: translate3d(-50%, 0, 0);
  }
}

/* ==========================================================================
   Reduced motion — a complete, calm, static page.
   The neon signs hold their lit state without flicker; the headlight trail
   sits at its first frame; nothing types — the full text is already in the
   DOM via the visually-hidden spans; the dawn bloom sits at full opacity.
   The page is fully readable; every animation simply holds its end state.
   ========================================================================== */

@media (prefers-reduced-motion: reduce) {
  .moonlit-js .moonlit-neon__tube,
  .moonlit-js .moonlit-street__tube {
    stroke-dashoffset: 0 !important;
    stroke: var(--ml-neon-bright);
    animation: none !important;
    transition: none !important;
  }

  .moonlit-js .moonlit-hero__statusdot,
  .moonlit-js .moonlit-status__cursor,
  .moonlit-js .moonlit-street__trail-row--a,
  .moonlit-js .moonlit-street__trail-row--b {
    animation: none !important;
  }

  .moonlit-js .moonlit-status__cursor {
    opacity: 0;
  }

  .moonlit-js .moonlit-street.is-running .moonlit-street__trail-row--a,
  .moonlit-js .moonlit-street.is-running .moonlit-street__trail-row--b {
    transform: none;
  }

  .moonlit-js .moonlit-hero__plate {
    transform: scale(1.06);
  }

  .moonlit-js .moonlit-track__line-fg {
    transition: none;
  }

  .moonlit-js [data-reveal] {
    opacity: 1;
    transform: none;
    transition: none;
  }

  .moonlit-handoff__dawn,
  .moonlit-handoff__warmglow {
    opacity: 1;
    transition: none;
  }
}
